1	//! R1 core — the shared HTML fragment skin every producer reuses.
2	//!
3	//! Three transforms, each pinned by observation (see workspace/BEHAVIOR.md §2–3
4	//! and QUERIES.log [S07]–[S12], [L03]–[L06]):
5	//!   * entity-escaping of producer-owned text;
6	//!   * the per-line postprocess: every logical line becomes its text (leading
7	//!     spaces as `&nbsp;` runs) followed by `<br/>` + newline;
8	//!   * the three JSON response envelopes: `{html,title}`, `{redirect}`,
9	//!     `{alert}` — compact, `html` key first, minimal string escaping.
10	
11	/// Entity-escape a run of producer-owned text.
12	///
13	/// The full escape set, forced through the help env line via a metachar
14	/// filename [L06] and matching the corpus-wide entity inventory [S10]:
15	/// `&`→`&amp;`, `<`→`&lt;`, `>`→`&gt;`, `"`→`&quot;`, `'`→`&#39;`.
16	/// Everything else (backslash included) passes through unchanged.
17	pub fn escape_text(s: &str) -> String {
18	    let mut out = String::with_capacity(s.len());
19	    for c in s.chars() {
20	        match c {
21	            '&' => out.push_str("&amp;"),
22	            '<' => out.push_str("&lt;"),
23	            '>' => out.push_str("&gt;"),
24	            '"' => out.push_str("&quot;"),
25	            '\'' => out.push_str("&#39;"),
26	            _ => out.push(c),
27	        }
28	    }
29	    out
30	}
31	
32	/// Apply the per-line postprocess to an assembled multi-line document.
33	///
34	/// Every newline-separated logical line — first, last, and empty ones alike —
35	/// is emitted as its text followed by `<br/>` and a real newline; a line's
36	/// LEADING run of spaces becomes one `&nbsp;` per space (interior runs are
37	/// left as spaces) [S03][S10]. An empty line is exactly `<br/>\n`. Tabs never
38	/// occur in observed fragments [S10] and pass through unchanged.
39	pub fn postprocess_lines(assembled: &str) -> String {
40	    let mut out = String::with_capacity(assembled.len() + assembled.len() / 3 + 8);
41	    for line in assembled.split('\n') {
42	        let text = line.trim_start_matches(' ');
43	        for _ in 0..line.len() - text.len() {
44	            out.push_str("&nbsp;");
45	        }
46	        out.push_str(text);
47	        out.push_str("<br/>\n");
48	    }
49	    out
50	}
51	
52	/// JSON string escaping as the observed envelopes use it: `"`→`\"`, `\`→`\\`,
53	/// newline→`\n`, tab→`\t` — the complete corpus escape inventory [S09]. Other
54	/// C0 controls never occur; they get the standard short forms / `\u00XX`
55	/// (documented arbitrary choice, BEHAVIOR.md §2). Non-ASCII stays raw UTF-8.
56	fn json_escape_into(out: &mut String, s: &str) {
57	    for c in s.chars() {
58	        match c {
59	            '"' => out.push_str("\\\""),
60	            '\\' => out.push_str("\\\\"),
61	            '\n' => out.push_str("\\n"),
62	            '\t' => out.push_str("\\t"),
63	            '\r' => out.push_str("\\r"),
64	            '\u{8}' => out.push_str("\\b"),
65	            '\u{c}' => out.push_str("\\f"),
66	            c if (c as u32) < 0x20 => {
67	                out.push_str(&format!("\\u{:04x}", c as u32));
68	            }
69	            c => out.push(c),
70	        }
71	    }
72	}
73	
74	/// Serialize an html fragment + pane title into the `{html,title}` envelope:
75	/// compact JSON, `html` key first [S07][S08][S12].
76	pub fn html_envelope(title: &str, html: &str) -> String {
77	    let mut out = String::with_capacity(html.len() + title.len() + 24);
78	    out.push_str("{\"html\":\"");
79	    json_escape_into(&mut out, html);
80	    out.push_str("\",\"title\":\"");
81	    json_escape_into(&mut out, title);
82	    out.push_str("\"}");
83	    out
84	}
85	
86	/// The `{redirect}` envelope: `{"redirect":"<url>"}` (1157 corpus instances
87	/// [S07]).
88	pub fn redirect_envelope(url: &str) -> String {
89	    let mut out = String::with_capacity(url.len() + 16);
90	    out.push_str("{\"redirect\":\"");
91	    json_escape_into(&mut out, url);
92	    out.push_str("\"}");
93	    out
94	}
95	
96	/// The `{alert}` envelope: `{"alert":"<msg>"}` (forced live via `del/path/help`
97	/// [L04]).
98	pub fn alert_envelope(msg: &str) -> String {
99	    let mut out = String::with_capacity(msg.len() + 13);
100	    out.push_str("{\"alert\":\"");
101	    json_escape_into(&mut out, msg);
102	    out.push_str("\"}");
103	    out
104	}
