1	//! Capture-corpus sweep — SPEC acceptance ladder rung 2 for R1.
2	//!
3	//! For every `main/message` / `main/rules` / `main/tactic` / `main/help`
4	//! response captured across the 81 crawl manifests, this test:
5	//!   1. reads the RAW envelope bytes (materialized by
6	//!      workspace/tools/extract_r1_raw.py into workspace/r1_raw/);
7	//!   2. decodes the `{html,title}` envelope and INVERTS the producer's skin —
8	//!      un-postprocessing the fragment into logical lines and slicing the
9	//!      opaque content out of the observed block skeleton;
10	//!   3. feeds the sliced content back through the producer and asserts the
11	//!      re-rendered response equals the captured bytes EXACTLY.
12	//! This exercises the frame + postprocess + envelope over the whole corpus
13	//! without a prover. A second test replays the curated round-1 byte targets
14	//! (producers/round1/targets/) the same way.
15	//!
16	//! The inversion is intentionally strict (panics on any unexpected shape) so
17	//! a capture that deviates from the modeled skeleton fails loudly instead of
18	//! being skipped.
19	
20	use std::fs;
21	use std::path::PathBuf;
22	
23	use producers_clean::model::{Content, ContentPane, EmptyRender, HeadedBlock, HelpPane};
24	use producers_clean::section::HELP_STATIC_HTML;
25	use producers_clean::{render_content_pane, render_help_pane};
26	
27	fn workspace_path(rel: &str) -> PathBuf {
28	    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join(rel)
29	}
30	
31	// ---------------------------------------------------------------------------
32	// Envelope decoding (strict: asserts the exact observed skeleton [S07][S08])
33	// ---------------------------------------------------------------------------
34	
35	/// Decode a JSON string starting after its opening quote; returns the decoded
36	/// text and the byte offset of the closing quote.
37	fn decode_json_string(s: &str) -> (String, usize) {
38	    let bytes = s.as_bytes();
39	    let mut out = String::new();
40	    let mut i = 0;
41	    loop {
42	        match bytes[i] {
43	            b'"' => return (out, i),
44	            b'\\' => {
45	                i += 1;
46	                match bytes[i] {
47	                    b'"' => out.push('"'),
48	                    b'\\' => out.push('\\'),
49	                    b'/' => out.push('/'),
50	                    b'n' => out.push('\n'),
51	                    b't' => out.push('\t'),
52	                    b'r' => out.push('\r'),
53	                    b'b' => out.push('\u{8}'),
54	                    b'f' => out.push('\u{c}'),
55	                    b'u' => {
56	                        let cp = u32::from_str_radix(&s[i + 1..i + 5], 16).unwrap();
57	                        i += 4;
58	                        out.push(char::from_u32(cp).expect("BMP escape"));
59	                    }
60	                    other => panic!("unexpected JSON escape \\{}", other as char),
61	                }
62	                i += 1;
63	            }
64	            _ => {
65	                let c = s[i..].chars().next().unwrap();
66	                out.push(c);
67	                i += c.len_utf8();
68	            }
69	        }
70	    }
71	}
72	
73	/// Split a raw `{"html":"…","title":"…"}` body into (html, title), asserting
74	/// the exact serialization skeleton.
75	fn decode_envelope(raw: &str) -> (String, String) {
76	    let rest = raw.strip_prefix("{\"html\":\"").expect("envelope opens with html key");
77	    let (html, end) = decode_json_string(rest);
78	    let rest = rest[end..]
79	        .strip_prefix("\",\"title\":\"")
80	        .expect("title key follows html");
81	    let (title, end) = decode_json_string(rest);
82	    assert_eq!(&rest[end..], "\"}", "envelope closes after title");
83	    (html, title)
84	}
85	
86	// ---------------------------------------------------------------------------
87	// Skin inversion: postprocessed fragment -> logical lines -> headed blocks
88	// ---------------------------------------------------------------------------
89	
90	/// Invert the per-line postprocess: `<br/>\n`-terminated lines with leading
91	/// `&nbsp;` runs back to plain lines with leading spaces.
92	fn unpostprocess(html: &str) -> Vec<String> {
93	    assert!(html.ends_with("<br/>\n"), "postprocessed fragment ends with a break");
94	    let mut lines: Vec<&str> = html.split("<br/>\n").collect();
95	    assert_eq!(lines.pop(), Some(""), "trailing separator");
96	    lines
97	        .iter()
98	        .map(|line| {
99	            let mut rest = *line;
100	            let mut n = 0;
101	            while let Some(r) = rest.strip_prefix("&nbsp;") {
102	                rest = r;
103	                n += 1;
104	            }
105	            format!("{}{}", " ".repeat(n), rest)
106	        })
107	        .collect()
108	}
109	
110	const P_OPEN: &str = "<p class=\"monospace rules\">";
111	
112	/// Parse logical lines into (leading-blank-line?, [(heading, body-lines)]).
113	fn parse_blocks(lines: &[String]) -> (bool, Vec<(String, Vec<String>)>) {
114	    let mut i = 0;
115	    let leading_blank = lines.first().is_some_and(|l| l.is_empty());
116	    if leading_blank {
117	        i = 1;
118	    }
119	    let mut blocks = Vec::new();
120	    while i < lines.len() {
121	        let heading = lines[i]
122	            .strip_prefix("<h2>")
123	            .and_then(|h| h.strip_suffix("</h2>"))
124	            .unwrap_or_else(|| panic!("expected heading line, got {:?}", lines[i]));
125	        i += 1;
126	        let first = lines[i]
127	            .strip_prefix(P_OPEN)
128	            .unwrap_or_else(|| panic!("expected paragraph open, got {:?}", lines[i]));
129	        let mut body = Vec::new();
130	        let mut cur = first.to_string();
131	        loop {
132	            if let Some(stripped) = cur.strip_suffix("</p>") {
133	                if !(stripped.is_empty() && body.is_empty()) {
134	                    body.push(stripped.to_string());
135	                }
136	                i += 1;
137	                break;
138	            }
139	            body.push(cur);
140	            i += 1;
141	            cur = lines[i].clone();
142	        }
143	        blocks.push((heading.to_string(), body));
144	    }
145	    (leading_blank, blocks)
146	}
147	
148	fn content(body: Vec<String>) -> Content {
149	    Content { lines: body }
150	}
151	
152	fn block(heading: &str, body: Vec<String>, when_empty: EmptyRender) -> HeadedBlock {
153	    HeadedBlock {
154	        heading: heading.into(),
155	        body: content(body),
156	        when_empty,
157	    }
158	}
159	
160	// ---------------------------------------------------------------------------
161	// Per-family reconstruction
162	// ---------------------------------------------------------------------------
163	
164	fn rebuild_message(html: &str, title: &str) -> ContentPane {
165	    assert_eq!(title, "Message theory");
166	    let (leading_blank, mut blocks) = parse_blocks(&unpostprocess(html));
167	    assert!(!leading_blank, "message pane has no leading blank");
168	    assert_eq!(blocks.len(), 3, "message pane emits exactly three sections");
169	    let heads: Vec<&str> = blocks.iter().map(|(h, _)| h.as_str()).collect();
170	    assert_eq!(
171	        heads,
172	        ["Signature", "Construction Rules", "Deconstruction Rules"]
173	    );
174	    ContentPane {
175	        title: title.into(),
176	        blocks: blocks
177	            .drain(..)
178	            .map(|(h, b)| block(&h, b, EmptyRender::Keep))
179	            .collect(),
180	    }
181	}
182	
183	fn rebuild_rules(html: &str, title: &str) -> ContentPane {
184	    assert_eq!(title, "Multiset rewriting rules and restrictions");
185	    let (leading_blank, parsed) = parse_blocks(&unpostprocess(html));
186	    let mut iter = parsed.into_iter().peekable();
187	
188	    // Macros slot: a real block, or the leading blank line when absent [L03].
189	    let macros_body = if iter.peek().is_some_and(|(h, _)| h == "Macros") {
190	        assert!(!leading_blank);
191	        iter.next().unwrap().1
192	    } else {
193	        assert!(leading_blank, "no macros block implies the blank slot");
194	        Vec::new()
195	    };
196	    let mut blocks = vec![block("Macros", macros_body, EmptyRender::BlankLine)];
197	
198	    let (h, b) = iter.next().expect("injective-facts section");
199	    assert_eq!(h, "Fact Symbols with Injective Instances");
200	    blocks.push(block(&h, b, EmptyRender::Keep));
201	
202	    let (h, b) = iter.next().expect("MSR section");
203	    assert_eq!(h, "Multiset Rewriting Rules");
204	    blocks.push(block(&h, b, EmptyRender::Keep));
205	
206	    // Restrictions: present, or omitted without residue [S10][S11].
207	    let restrictions = match iter.next() {
208	        Some((h, b)) => {
209	            assert_eq!(h, "Restrictions of the Set of Traces");
210	            b
211	        }
212	        None => Vec::new(),
213	    };
214	    blocks.push(block(
215	        "Restrictions of the Set of Traces",
216	        restrictions,
217	        EmptyRender::Omit,
218	    ));
219	    assert!(iter.next().is_none(), "no further sections");
220	    ContentPane {
221	        title: title.into(),
222	        blocks,
223	    }
224	}
225	
226	fn rebuild_tactic(html: &str, title: &str) -> ContentPane {
227	    assert_eq!(title, "Tactics");
228	    let (leading_blank, mut blocks) = parse_blocks(&unpostprocess(html));
229	    assert!(!leading_blank);
230	    assert_eq!(blocks.len(), 1);
231	    let (h, b) = blocks.pop().unwrap();
232	    assert_eq!(h, "Tactic(s)");
233	    ContentPane {
234	        title: title.into(),
235	        blocks: vec![block(&h, b, EmptyRender::Keep)],
236	    }
237	}
238	
239	/// Reverse of `escape_text` for the env-line fields (strict).
240	fn unescape_entities(s: &str) -> String {
241	    let mut out = String::with_capacity(s.len());
242	    let mut rest = s;
243	    while let Some(i) = rest.find('&') {
244	        out.push_str(&rest[..i]);
245	        rest = &rest[i..];
246	        let (c, len) = if rest.starts_with("&amp;") {
247	            ('&', 5)
248	        } else if rest.starts_with("&lt;") {
249	            ('<', 4)
250	        } else if rest.starts_with("&gt;") {
251	            ('>', 4)
252	        } else if rest.starts_with("&quot;") {
253	            ('"', 6)
254	        } else if rest.starts_with("&#39;") {
255	            ('\'', 5)
256	        } else {
257	            panic!("unknown entity at {:?}", &rest[..rest.len().min(8)]);
258	        };
259	        out.push(c);
260	        rest = &rest[len..];
261	    }
262	    out.push_str(rest);
263	    out
264	}
265	
266	fn rebuild_help(html: &str, title: &str) -> HelpPane {
267	    let static_at = html.find("<div id=\"help\">").expect("static help block");
268	    assert_eq!(&html[static_at..], HELP_STATIC_HTML, "invariant static block");
269	    let env = html[..static_at]
270	        .strip_prefix("<p>Theory: ")
271	        .and_then(|e| e.strip_suffix("</p>"))
272	        .expect("env line shape");
273	    let (pre, banner) = match env.find("<div class=\"wf-warning\"") {
274	        Some(i) => (&env[..i], &env[i..]),
275	        None => (env, ""),
276	    };
277	    let pre = pre.strip_suffix(") ").expect("env line closes with `) `");
278	    let (name, rest) = pre.split_once(" (Loaded at ").expect("Loaded-at marker");
279	    let (time, origin) = rest.split_once(" from ").expect("from marker");
280	    let name = unescape_entities(name);
281	    assert_eq!(title, format!("Theory: {name}"));
282	    HelpPane {
283	        theory_name: name,
284	        load_time: unescape_entities(time),
285	        origin: unescape_entities(origin),
286	        wf_banner_html: banner.into(),
287	    }
288	}
289	
290	fn replay(family: &str, raw: &str) -> String {
291	    let (html, title) = decode_envelope(raw);
292	    match family {
293	        "message" => render_content_pane(&rebuild_message(&html, &title)),
294	        "rules" => render_content_pane(&rebuild_rules(&html, &title)),
295	        "tactic" => render_content_pane(&rebuild_tactic(&html, &title)),
296	        "help" => render_help_pane(&rebuild_help(&html, &title)),
297	        other => panic!("unknown family {other}"),
298	    }
299	}
300	
301	// ---------------------------------------------------------------------------
302	// The sweeps
303	// ---------------------------------------------------------------------------
304	
305	/// All 81 manifests x 4 center fragments: slice, re-render, byte-compare the
306	/// whole response body (envelope included).
307	#[test]
308	fn corpus_sweep_all_manifests() {
309	    let dir = workspace_path("../r1_raw");
310	    let mut count = 0;
311	    let mut per_family = [0usize; 4];
312	    let mut entries: Vec<_> = fs::read_dir(&dir)
313	        .expect("workspace/r1_raw materialized (tools/extract_r1_raw.py)")
314	        .map(|e| e.unwrap().path())
315	        .filter(|p| p.extension().is_some_and(|e| e == "raw"))
316	        .collect();
317	    entries.sort();
318	    for path in entries {
319	        let stem = path.file_stem().unwrap().to_str().unwrap();
320	        let family = stem.rsplit("__main_").next().unwrap();
321	        let raw = fs::read_to_string(&path).unwrap();
322	        let rendered = replay(family, &raw);
323	        assert_eq!(rendered, raw, "byte mismatch replaying {stem}");
324	        per_family[["message", "rules", "tactic", "help"]
325	            .iter()
326	            .position(|f| *f == family)
327	            .unwrap()] += 1;
328	        count += 1;
329	    }
330	    assert_eq!(count, 324, "81 manifests x 4 fragments");
331	    assert_eq!(per_family, [81; 4]);
332	}
