334	/// Live-probe replays (workspace/r1_live/, raw bodies captured from the
335	/// oracle server on theories NOT in the crawl corpus): the own-authored
336	/// metachar-filename EscProbe theory [L06] and the macros-bearing
337	/// MacroGlobalVarNSPK3 [L03] — the only observed macros-present rules pane.
338	#[test]
339	fn live_probe_replays() {
340	    let dir = workspace_path("../r1_live");
341	    let mut count = 0;
342	    let mut entries: Vec<_> = fs::read_dir(&dir)
343	        .expect("workspace/r1_live materialized (QUERIES.log [L03][L06][L07])")
344	        .map(|e| e.unwrap().path())
345	        .filter(|p| p.extension().is_some_and(|e| e == "raw"))
346	        .collect();
347	    entries.sort();
348	    for path in entries {
349	        let stem = path.file_stem().unwrap().to_str().unwrap();
350	        let family = stem.rsplit("__main_").next().unwrap();
351	        let raw = fs::read_to_string(&path).unwrap();
352	        assert_eq!(replay(family, &raw), raw, "byte mismatch replaying {stem}");
353	        count += 1;
