358	/// The curated round-1 byte targets (producers/round1/targets/): decoded
359	/// fragment + title files; re-render and byte-compare fragment and title.
360	#[test]
361	fn round1_materialized_targets() {
362	    let dir = workspace_path("../../round1/targets");
363	    let mut count = 0;
364	    let mut entries: Vec<_> = fs::read_dir(&dir)
365	        .expect("round1/targets materialized")
366	        .map(|e| e.unwrap().path())
367	        .filter(|p| p.extension().is_some_and(|e| e == "html"))
368	        .collect();
369	    entries.sort();
370	    for path in entries {
371	        let stem = path.file_stem().unwrap().to_str().unwrap();
372	        let family = stem.rsplit("_main_").next().unwrap();
373	        let html = fs::read_to_string(&path).unwrap();
374	        let title = fs::read_to_string(path.with_extension("title")).unwrap();
375	        let rebuilt_envelope = match family {
376	            "message" => render_content_pane(&rebuild_message(&html, &title)),
377	            "rules" => render_content_pane(&rebuild_rules(&html, &title)),
378	            "tactic" => render_content_pane(&rebuild_tactic(&html, &title)),
379	            "help" => render_help_pane(&rebuild_help(&html, &title)),
380	            other => panic!("unknown family {other}"),
381	        };
382	        let (out_html, out_title) = decode_envelope(&rebuilt_envelope);
383	        assert_eq!(out_html, html, "fragment byte mismatch for {stem}");
384	        assert_eq!(out_title, title, "title mismatch for {stem}");
385	        count += 1;
386	    }
387	    assert_eq!(count, 44, "11 curated labels x 4 fragments");
388	}
